INSERT INTO documents (title, content, category, source) VALUES ('Linux', 'Linux is a popular, open-source operating system (OS) based on Unix, designed for versatility and security across devices ranging from home computers to the world’s top supercomputers, cars, and,home appliances. It consists of a kernel that manages hardware and a user space for applications. Linux is free, allowing users to run, study, change, and redistribute it, making it a common alternative to proprietary systems like Windows and macO', 'Operating System', 'OS');
INSERT INTO documents (title, content, category, source) VALUES ('Windows', 'Windows is a proprietary graphical operating system developed and marketed by Microsoft. Windows is grouped into families that cater to particular sectors of the computing industry – Windows for personal computers, Windows Server for servers, and Windows IoT for embedded systems.', 'Operating System', 'OS');
INSERT INTO documents (title, content, category, source) VALUES ('MacOS', 'Apples proprietary Unix-based operating system designed for Mac computers, known for its elegant design, robust security, and seamless integration with the Apple ecosystem, including iPhone and Watch. The latest versions focus on AI features (Apple Intelligence), enhanced security, and refined productivity tools', 'Operating System', 'OS');
INSERT INTO documents (title, content, category, source) VALUES ('Alpine linux OS', 'Alpine Linux is a Linux distribution that uses musl, BusyBox, and OpenRC instead of glibc, GNU Core Utilities, and systemd, respectively. This makes Alpine one of few Linux distributions not to be based on the latter', 'Operating System', 'OS');
